import { t } from "i18next";
import { useForm } from "react-hook-form"
import { zodResolver } from "@hookform/resolvers/zod"
import { useAuth } from "@/providers/AuthContext";

import { createPublicRestaurant } from "../../lib/firebase/restaurants"
import { createPublickRestaurantSchema } from "@/lib/validators/createPublickRestaurantScheme";
import { CreatePublicRestaurantForm } from "@/data/types/createPublicRestaurantForm";
import { CUISINES } from "@/data/constans/cusines";

type Props = {
    restaurantId?: string
}
export const RestaurantForm = ({ restaurantId }: Props) => {
    const {
        register,
        handleSubmit,
        formState: { errors, isSubmitting },
        reset
    } = useForm<CreatePublicRestaurantForm>({
        resolver: zodResolver(createPublickRestaurantSchema),
        defaultValues: {
            name: "",
            city: "",
            category: [],
            shortDescription: "",
            coverImage: "",
            delivery: false,
        }
    })
    const { user } = useAuth()

    const onSubmit = async (data: CreatePublicRestaurantForm) => {
        if (!restaurantId || !user) return
        const newId = await createPublicRestaurant(data, user.uid)
        reset()
        alert("Dodano restauracje")
    }

    return (
        <div className="rounded-lg border border-black-200 p-3 flex flex-col items-center justify-center w-[30vw]">
            <h2 className="text-lg font-medium mb-4">{t("owner_dashboard_add_restaurants_header")}</h2>
            <form className="w-full p-10" onSubmit={handleSubmit(onSubmit)}>

                <div className="p-2">
                    <input {...register("name")} placeholder="Nazwa restauracji" className="w-full p-6 bg-white rounded-lg border border-black-200" />
                    <p className="p-2">{errors.name?.message}</p>
                </div>
                <div className="p-2">
                    <input {...register("city")} placeholder="Miejscowość" className="w-full p-6 bg-white rounded-lg border border-black-200" />
                    <p className="p-2">{errors.city?.message}</p>
                </div>
                <div className="p-2">
                    <p className="mb-2 font-medium">Rodzaj kuchni</p>
                    {CUISINES.map((cusin) => (
                        <label key={cusin} className="flex items-center gap-2 p-2 border rounded-lg cursor-pointer" >
                            <input type="checkbox" value={cusin} {...register("category")} />
                            <span>{cusin}</span>
                        </label>
                    ))}
                </div>
                <div className="p-2">
                    <textarea {...register("shortDescription")} placeholder="Krótki opis lokalu..." className="w-full p-6 bg-white rounded-lg border border-black-200" />
                    <p className="p-2">{errors.shortDescription?.message}</p>
                </div>
                <div className="p-2">
                    <input {...register("coverImage")} placeholder="URL zdjęcia" className="w-full p-6 bg-white rounded-lg border border-black-200" />
                    <p className="p-2">{errors.coverImage?.message}</p>
                </div>
                <div className="p-2">
                    <label className="p-5">
                        <input type="checkbox" {...register("delivery")} className="p-6" />
                        <span className="p-2">Dostawa</span>
                    </label>
                </div>
                <div className="
                flex 
                items-center 
                justify-center
                px-6 py-3
                bg-white text-black
                rounded-lg
                transition-colors duration-300
                hover:bg-blue-600 
                hover:text-white">
                    <button type="submit" disabled={isSubmitting}>{isSubmitting ? "Zapisywanie..." : "Dodaj restaurację"}</button>
                </div>

            </form >
        </div >
    );
}  